parameters.query:
UPDATE matches
SET notified = TRUE, notified_at = CURRENT_TIMESTAMP
WHERE match_id = ANY($1);

parameters.functionCode:
// Log notification results
const emailsSent = $input.all().length;
const timestamp = new Date().toISOString();

console.log(`User Notification workflow completed at ${timestamp}`);
console.log(`Emails sent: ${emailsSent}`);

return [{
  json: {
    success: true,
    emails_sent: emailsSent,
    timestamp: timestamp
  }
}];
